/* 文件头注释：动态规划算法，模拟手指在键盘上的移动 */
#include <bits/stdc++.h>
using namespace std;

// 定义键盘上每个键的相邻键
const vector<vector<char>> adjacent = {
    {'q', 'w'}, {'w', 'e', 'q'}, {'e', 'r', 'w'}, {'r', 't', 'e'}, {'t', 'y', 'r'}, {'y', 'u', 't'}, {'u', 'i', 'y'}, {'i', 'o', 'u'}, {'o', 'p', 'i'}, {'p', 'o'},
